Add-Type -AssemblyName System.Drawing; $imagePath = Join-Path (Get-Location) "assets\icon.png"; $outputPath = Join-Path (Get-Location) "assets\tray_icon.png"; $bmp = [System.Drawing.Bitmap]::FromFile($imagePath); $size = 64; $paddingRatio = 0.3; $innerSize = [int]($size * (1 - $paddingRatio)); $offset = [int](($size - $innerSize) / 2); $destBmp = New-Object System.Drawing.Bitmap($size, $size); $graphics = [System.Drawing.Graphics]::FromImage($destBmp); $graphics.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic; $graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality; $graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::HighQuality; $graphics.Clear([System.Drawing.Color]::Transparent); $graphics.DrawImage($bmp, $offset, $offset, $innerSize, $innerSize); $destBmp.Save($outputPath, [System.Drawing.Imaging.ImageFormat]::Png); $graphics.Dispose(); $destBmp.Dispose(); $bmp.Dispose(); Write-Host "Saved to $outputPath"
